# shapes_module.spy - Shape implementations with inheritance and interfaces
from types_module import Entity, Point, IPrintable, IMeasurable, ShapeCategory

# Circle class with multiple interface implementations
class Circle(Entity, IPrintable, IMeasurable):
    center: Point
    radius: float

    def __init__(self, name: str, center: Point, radius: float):
        super().__init__(name, ShapeCategory.GEOMETRIC)
        self.center = center
        self.radius = radius

    @override
    def describe(self) -> str:
        return f"Circle '{self.name}' at ({self.center.x}, {self.center.y}) with radius {self.radius}"

    @override
    def format(self) -> str:
        return f"[Circle: r={self.radius}]"

    @override
    def measure(self) -> float:
        # Return area: pi * r^2
        return 3.14159 * self.radius * self.radius

# Rectangle class
class Rectangle(Entity, IPrintable, IMeasurable):
    top_left: Point
    width: float
    height: float

    def __init__(self, name: str, top_left: Point, width: float, height: float):
        super().__init__(name, ShapeCategory.GEOMETRIC)
        self.top_left = top_left
        self.width = width
        self.height = height

    @override
    def describe(self) -> str:
        return f"Rectangle '{self.name}' at ({self.top_left.x}, {self.top_left.y}) sized {self.width}x{self.height}"

    @override
    def format(self) -> str:
        return f"[Rectangle: {self.width}x{self.height}]"

    @override
    def measure(self) -> float:
        # Return area: width * height
        return self.width * self.height

