# utils_module.spy - Utility functions and constants
from types_module import Point, IPrintable, IMeasurable, ShapeCategory

# Get the category name as a properly formatted string
def get_category_name(category: ShapeCategory) -> str:
    return category.name

# Calculate total measurement for a list of measurable objects
# NOTE: Takes list[IMeasurable] directly - caller must build with append
def total_measurement(items: list[IMeasurable]) -> float:
    total: float = 0.0
    for item in items:
        total += item.measure()
    return total

# Format all printable items in a list
# NOTE: Takes list[IPrintable] directly - caller must build with append
def format_all(items: list[IPrintable]) -> list[str]:
    result: list[str] = []
    for item in items:
        result.append(item.format())
    return result

# Static function to create a point at the origin
def origin_point() -> Point:
    return Point(0.0, 0.0)
